const mongoose = require\("mongoose"\);
async function run\(\) {
  await mongoose.connect\("mongodb://root:root@localhost:27018/mercadinho?authSource=admin"\);
  const db = mongoose.connection.db;

  const product = await db.collection\("products"\).findOne\({ name: { $regex: /coca/i } }\);
  const tomorrow = new Date\(\);
  tomorrow.setDate\(tomorrow.getDate\(\) + 1\);
  tomorrow.setHours\(23, 59, 59, 0\);

  const purchasePrice = 0.50;
  const originalSalePrice = product.salePrice; // 1
  // 1 dia = 50% desconto sobre margem
  const margin = originalSalePrice - purchasePrice; // 0.50
  const reducedMargin = margin * \(1 - 50/100\); // 0.25
  const currentPrice = Number\(\(purchasePrice + reducedMargin\).toFixed\(2\)\); // 0.75

  const result = await db.collection\("batches"\).insertOne\({
    product: product._id,
    location: "default",
    batchCode: null,
    quantity: 10,
    expiryDate: tomorrow,
    purchasePrice: purchasePrice,
    originalSalePrice: originalSalePrice,
    currentPrice: currentPrice,
    discountPercent: 50,
    manualDiscount: false,
    createdAt: new Date\(\),
    updatedAt: new Date\(\)
  }\);

  console.log\("Lote criado:", result.insertedId.toString\(\)\);
  console.log\("Produto:", product.name\);
  console.log\("Vencimento:", tomorrow.toISOString\(\)\);
  console.log\("Preço original:", originalSalePrice\);
  console.log\("Preço com desconto:", currentPrice\);
  console.log\("Desconto:", "50%"\);

  await mongoose.disconnect\(\);
}
run\(\).catch\(e => { console.error\(e\); process.exit\(1\); }\);
')

